import { useEffect, useState } from "react";

import "./App.css";
import SearchIcon from "./search.svg";

import MovieCard from "./MovieCard";

// 3782fe82
const API_URL = "http://www.omdbapi.com?apikey=3782fe82";

// const movie1 = {
//     "Title": "Deadpool",
//     "Year": "2016",
//     "imdbID": "tt1431045",
//     "Type": "movie",
//     "Poster": "https://m.media-amazon.com/images/M/MV5BYzE5MjY1ZDgtMTkyNC00MTMyLThhMjAtZGI5OTE1NzFlZGJjXkEyXkFqcGdeQXVyNjU0OTQ0OTY@._V1_SX300.jpg"
// }

const App = () => {
    const [movies, setMovies] = useState([]);

    const [searchTerm , setSearchTerm] = useState("");

    const searchMovies = async (title) => {
        const response = await fetch(`${API_URL}&s=${title}`);
        const data = await response.json();

        setMovies(data.Search);
    }

    useEffect(() => {
        // searchMovies("deadpool");
    }, [])

    return (
        <div className="app">
            <h1>MovieFox</h1>

            <div className="search">
                <input
                    placeholder="Enter Movie Name"
                    value= {searchTerm}
                    onChange={(e) => {setSearchTerm(e.target.value)}}
                />
                <img
                    src={SearchIcon}
                    alt="search"
                    onClick={()=> {searchMovies(searchTerm)}}
                    onKeyUp={(e)=> { if(e.key === "Enter" === 13) searchMovies(searchTerm); }}
                />
            </div>

            {
                movies?.length > 0
                    ? (
                        <div className="container">
                            {
                                movies.map((movie) => {
                                    return (
                                        <MovieCard movie1={movie} />
                                    )
                                })
                            }
                        </div>
                    ) : (
                        <div className="empty">
                            <h2>Movie Not Found</h2>
                        </div>
                    )
            }


        </div>
    )
}

export default App;
